def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = np.inf if item > 0 else 0
            continue
        if item < 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 3:
            base = ratio ** 4
            penalty = 0
            for k in range(1, 6):
                penalty += (ratio ** (k * 2)) / (k ** 2 + 1)
            priorities[i] = base + penalty + np.log1p(ratio)
        elif 2 < ratio <= 3:
            penalty = 0
            for k in range(1, 5):
                penalty += ((-1) ** k) * (ratio ** (k + 2)) / (k + 3)
            priorities[i] = (ratio ** 3) + penalty + np.exp(-ratio)
        elif 1 < ratio <= 2:
            summation = 0
            for p in range(1, 10):
                sign = 1 if p % 3 == 0 else -1
                summation += sign * (ratio ** p) / (p + 1)
            priorities[i] = abs(summation * np.sin(ratio * np.pi)) + ratio
        elif 0.7 < ratio <= 1:
            score = 0
            for j in range(1, 8):
                sign = (-1) ** (j + 1)
                score += sign * (ratio ** j) / (j**1.5)
            multiplier = 20 if ratio < 0.85 else 8
            priorities[i] = abs(score) * multiplier + np.sqrt(ratio)
        elif 0.3 < ratio <= 0.7:
            score = 0
            for q in range(1, 5):
                for r in range(1, 3):
                    score += (ratio ** (q + r)) / (q * r + 1)
            priorities[i] = score * 12 + (capacity % (item + 1))
        elif 0 < ratio <= 0.3:
            acc = 0
            for m in range(1, 20):
                if m % 2 == 0:
                    acc -= (ratio ** m) / (2 * m)
                else:
                    acc += (ratio ** m) / m
            priorities[i] = abs(acc) * 25 + np.log1p(capacity)
        else:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
        if priorities[i] != np.inf and priorities[i] > 1000:
            for _ in range(3):
                priorities[i] = priorities[i] / 2 + np.sqrt(priorities[i])
        if priorities[i] < 0:
            priorities[i] = 0
    return priorities
